using System.IO;

public class TerrainMapExporter : MonoBehaviour
{
    [Header("References")]
    public ProcedualGenerator terrainGenerator;

    [Header("Export Settings")]
    public string exportFolder = "Assets/ExportedMaps";
    public bool autoExportOnStart = false;

    [Header("Visualization")]
    public bool visualizeHeightmap = true;
    public bool visualizeBiomeMap = true;

    private Texture2D heightmapTexture;
    private Texture2D biomeMapTexture;

    private void Start()
    {
        if (terrainGenerator == null)
        {
            terrainGenerator = GetComponent<ProcedualGenerator>();
        }

        if (autoExportOnStart)
        {
            ExportMaps();
        }
    }

    /// <summary>
    /// Exports the heightmap and biome map from the terrain generator
    /// </summary>
    public void ExportMaps()
    {
        if (terrainGenerator == null)
        {
            Debug.LogError("TerrainMapExporter: ProcedualGenerator reference is null");
            return;
        }

        // Get terrain data
        int resolution = terrainGenerator.resolution;

        // Access the private fields through reflection (if needed)
        // or ensure ProcedualGenerator exposes the necessary data
        if (!TryGetTerrainData(out Vector3[] verts, out Vector4[] uv2s, out Vector4[] uv3s))
        {
            Debug.LogError("TerrainMapExporter: Failed to retrieve terrain data from ProcedualGenerator");
            return;
        }

        // Generate textures
        heightmapTexture = GenerateHeightmapTexture(verts, resolution);
        biomeMapTexture = GenerateBiomeMapTexture(uv2s, uv3s, resolution);

        // Save to disk
        CreateExportFolder();
        SaveTexture(heightmapTexture, "heightmap.png");
        SaveTexture(biomeMapTexture, "biomemap.png");

        Debug.Log($"TerrainMapExporter: Successfully exported maps to {Path.GetFullPath(exportFolder)}");
    }

    /// <summary>
    /// Generates a heightmap texture from vertex positions
    /// </summary>
    private Texture2D GenerateHeightmapTexture(Vector3[] verts, int resolution)
    {
        Texture2D heightmap = new Texture2D(resolution, resolution, TextureFormat.RFloat, false, true);
        float[] heights = new float[resolution * resolution];

        // Find min and max height for normalization
        float minHeight = float.MaxValue;
        float maxHeight = float.MinValue;

        for (int i = 0; i < verts.Length; i++)
        {
            float height = verts[i].y;
            heights[i] = height;
            if (height < minHeight) minHeight = height;
            if (height > maxHeight) maxHeight = height;
        }

        // Normalize heights to 0-1 range
        float heightRange = maxHeight - minHeight;
        if (heightRange < 0.001f) heightRange = 1f; // Prevent division by zero

        Color[] pixels = new Color[resolution * resolution];
        for (int i = 0; i < heights.Length; i++)
        {
            float normalizedHeight = (heights[i] - minHeight) / heightRange;
            pixels[i] = new Color(normalizedHeight, normalizedHeight, normalizedHeight, 1f);
        }

        heightmap.SetPixels(pixels);
        heightmap.Apply();

        Debug.Log($"Heightmap generated: {resolution}x{resolution}, Height range: {minHeight:F2} to {maxHeight:F2}");
        return heightmap;
    }

    /// <summary>
    /// Generates a biome map texture from biome indices
    /// </summary>
    private Texture2D GenerateBiomeMapTexture(Vector4[] uv2s, Vector4[] uv3s, int resolution)
    {
        Texture2D biomeMap = new Texture2D(resolution, resolution, TextureFormat.RGBA32, false, true);
        Color[] pixels = new Color[resolution * resolution];

        // Get biome count
        int biomeCount = Mathf.Min(3, 4); // Max 3 biomes per pixel (stored in uv2 and uv3)

        for (int i = 0; i < pixels.Length; i++)
        {
            Vector4 indices = uv2s[i];
            Vector4 weights = uv3s[i];

            // Create color based on primary biome (you can modify this to blend colors)
            int biomeIndex = (int)indices.x;
            float weight = weights.x;

            // Normalize biome index to 0-1 for visualization (divide by max possible biomes)
            float biomeNormalized = biomeIndex / Mathf.Max(1, 19f); // Assuming max 20 biomes (0-19)

            // Create RGB from biome index and include weight in alpha
            pixels[i] = new Color(biomeNormalized, weight, (int)indices.y / 20f, 1f);
        }

        biomeMap.SetPixels(pixels);
        biomeMap.Apply();

        Debug.Log($"Biome map generated: {resolution}x{resolution}");
        return biomeMap;
    }

    /// <summary>
    /// Attempts to retrieve terrain data from ProcedualGenerator
    /// </summary>
    private bool TryGetTerrainData(out Vector3[] verts, out Vector4[] uv2s, out Vector4[] uv3s)
    {
        verts = null;
        uv2s = null;
        uv3s = null;

        try
        {
            // Try to access the fields directly
            var vertsField = typeof(ProcedualGenerator).GetField("verts", 
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var uv2Field = typeof(ProcedualGenerator).GetField("uv2s", 
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var uv3Field = typeof(ProcedualGenerator).GetField("uv3s", 
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

            if (vertsField != null && uv2Field != null && uv3Field != null)
            {
                verts = (Vector3[])vertsField.GetValue(terrainGenerator);
                uv2s = (Vector4[])uv2Field.GetValue(terrainGenerator);
                uv3s = (Vector4[])uv3Field.GetValue(terrainGenerator);

                if (verts != null && uv2s != null && uv3s != null && verts.Length > 0)
                {
                    return true;
                }
            }
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"ReflectionError: {ex.Message}");
        }

        return false;
    }

    /// <summary>
    /// Creates the export folder if it doesn't exist
    /// </summary>
    private void CreateExportFolder()
    {
        string fullPath = Path.Combine(Application.dataPath, "..", exportFolder);
        if (!Directory.Exists(fullPath))
        {
            Directory.CreateDirectory(fullPath);
        }
    }

    /// <summary>
    /// Saves a texture as PNG file
    /// </summary>
    private void SaveTexture(Texture2D texture, string filename)
    {
        if (texture == null)
        {
            Debug.LogError($"TerrainMapExporter: Cannot save null texture");
            return;
        }

        CreateExportFolder();
        string fullPath = Path.Combine(Application.dataPath, "..", exportFolder, filename);
        byte[] pngData = texture.EncodeToPNG();
        File.WriteAllBytes(fullPath, pngData);
        Debug.Log($"TerrainMapExporter: Saved {filename} to {fullPath}");
    }

    /// <summary>
    /// Returns the generated heightmap texture (for runtime use)
    /// </summary>
    public Texture2D GetHeightmapTexture() => heightmapTexture;

    /// <summary>
    /// Returns the generated biome map texture (for runtime use)
    /// </summary>
    public Texture2D GetBiomeMapTexture() => biomeMapTexture;
}
