using UnityEngine;

[CustomEditor(typeof(TerrainMapExporter))]
public class TerrainMapExporterEditor : Editor
{
    public override void OnInspectorGUI()
    {
        DrawDefaultInspector();

        TerrainMapExporter exporter = (TerrainMapExporter)target;

        EditorGUILayout.Space();
        EditorGUILayout.LabelField("Export Controls", EditorStyles.boldLabel);

        if (GUILayout.Button("Export Heightmap & Biome Map", GUILayout.Height(40)))
        {
            exporter.ExportMaps();
        }

        EditorGUILayout.HelpBox(
            "This will export the heightmap and biome map as PNG files to the specified export folder. " +
            "Make sure the terrain has been generated first.",
            MessageType.Info
        );
    }
}
