    }

    /// <summary>
    /// Generates terrain data for a specific chunk by running the compute shader
    /// </summary>
    private bool GenerateChunkData(int chunkX, int chunkZ, int resolution, 
        out Vector3[] verts, out Vector4[] uv2s, out Vector4[] uv3s)
    {
        verts = null;
        uv2s = null;
        uv3s = null;

        try
        {
            // Get the compute shader and biome data from the generator
            var csField = typeof(ProcedualGenerator).GetField("meshCS", 
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var biomeDataField = typeof(ProcedualGenerator).GetField("biomeData",
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

            if (csField == null || biomeDataField == null)
            {
                Debug.LogError("TerrainMapExporter: Could not access compute shader or biome data");
                return false;
            }

            ComputeShader meshCS = (ComputeShader)csField.GetValue(terrainGenerator);
            BiomeData biomeData = (BiomeData)biomeDataField.GetValue(terrainGenerator);

            if (meshCS == null || biomeData == null)
            {
                Debug.LogError("TerrainMapExporter: Compute shader or biome data is null");
                return false;
            }

            int vertexCount = resolution * resolution;

            // Create temporary buffers
            GraphicsBuffer vertexBuffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, vertexCount, sizeof(float) * 3);
            GraphicsBuffer normalBuffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, vertexCount, sizeof(float) * 3);
            GraphicsBuffer uv2Buffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, vertexCount, sizeof(float) * 4);
            GraphicsBuffer uv3Buffer = new GraphicsBuffer(GraphicsBuffer.Target.Structured, vertexCount, sizeof(float) * 4);

            int kernel = meshCS.FindKernel("CSMain");
            meshCS.SetBuffer(kernel, "vertices", vertexBuffer);
            meshCS.SetBuffer(kernel, "normals", normalBuffer);
            meshCS.SetBuffer(kernel, "uv2", uv2Buffer);
            meshCS.SetBuffer(kernel, "uv3", uv3Buffer);

            meshCS.SetInt("resolution", resolution);

            // Calculate offsets for this chunk
            float chunkSize = resolution - 1;
            float xOffset = terrainGenerator.transform.position.x + chunkX * chunkSize;
            float yOffset = terrainGenerator.transform.position.z + chunkZ * chunkSize;

            meshCS.SetFloat("xOffset", xOffset);
            meshCS.SetFloat("yOffset", yOffset);

            // Get other parameters from the generator
            var moistField = typeof(ProcedualGenerator).GetField("moistFrequency",
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            var tempField = typeof(ProcedualGenerator).GetField("tempFrequency",
                System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);

            float moistFreq = (float)moistField?.GetValue(terrainGenerator) ?? 0.0005f;
            float tempFreq = (float)tempField?.GetValue(terrainGenerator) ?? 0.0003f;

            meshCS.SetFloat("moistFreq", moistFreq);
            meshCS.SetFloat("tempFreq", tempFreq);
            meshCS.SetInt("biomeCount", biomeData.biomes.Count);

            // Create and set biome buffers
            ComputeBuffer freqBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(float));
            ComputeBuffer ampBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(float));
            ComputeBuffer lacBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(float));
            ComputeBuffer gainBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(float));
            ComputeBuffer octBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(int));
            ComputeBuffer tempBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(int));
            ComputeBuffer moistBuffer = new ComputeBuffer(biomeData.biomes.Count, sizeof(int));

            float[] frequencys = new float[biomeData.biomes.Count];
            float[] amplitudes = new float[biomeData.biomes.Count];
            float[] lacunarities = new float[biomeData.biomes.Count];
            float[] gains = new float[biomeData.biomes.Count];
            int[] octaves = new int[biomeData.biomes.Count];
            int[] biometemps = new int[biomeData.biomes.Count];
            int[] biomemoist = new int[biomeData.biomes.Count];

            for (int i = 0; i < biomeData.biomes.Count; i++)
            {
                frequencys[i] = biomeData.biomes[i].frequency;
                amplitudes[i] = biomeData.biomes[i].amplitude;
                lacunarities[i] = biomeData.biomes[i].lacunarity;
                gains[i] = biomeData.biomes[i].gain;
                octaves[i] = biomeData.biomes[i].octaves;
                biometemps[i] = (int)biomeData.biomes[i].temperature;
                biomemoist[i] = (int)biomeData.biomes[i].moisture;
            }

            freqBuffer.SetData(frequencys);
            ampBuffer.SetData(amplitudes);
            lacBuffer.SetData(lacunarities);
            gainBuffer.SetData(gains);
            octBuffer.SetData(octaves);
            tempBuffer.SetData(biometemps);
            moistBuffer.SetData(biomemoist);

            meshCS.SetBuffer(kernel, "frequencys", freqBuffer);
            meshCS.SetBuffer(kernel, "amplitudes", ampBuffer);
            meshCS.SetBuffer(kernel, "lacunarities", lacBuffer);
            meshCS.SetBuffer(kernel, "gains", gainBuffer);
            meshCS.SetBuffer(kernel, "octaves", octBuffer);
            meshCS.SetBuffer(kernel, "biometemps", tempBuffer);
            meshCS.SetBuffer(kernel, "biomemoist", moistBuffer);

            // Run the compute shader
            int groups = Mathf.CeilToInt(resolution / 16f);
            meshCS.Dispatch(kernel, groups, groups, 1);

            // Read back the data
            verts = new Vector3[vertexCount];
            uv2s = new Vector4[vertexCount];
            uv3s = new Vector4[vertexCount];

            vertexBuffer.GetData(verts);
            uv2Buffer.GetData(uv2s);
            uv3Buffer.GetData(uv3s);

            // Release temporary buffers
            vertexBuffer.Release();
            normalBuffer.Release();
            uv2Buffer.Release();
            uv3Buffer.Release();
            freqBuffer.Release();
            ampBuffer.Release();
            lacBuffer.Release();
            gainBuffer.Release();
            octBuffer.Release();
            tempBuffer.Release();
            moistBuffer.Release();

            return true;
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"TerrainMapExporter: Error generating chunk data: {ex.Message}\n{ex.StackTrace}");
            return false;
        }
    }

    /// <summary>
    /// Copies chunk data into the combined array at the appropriate position
    /// </summary>
    private void CopyChunkToCombined(Vector3[] chunkVerts, Vector4[] chunkUV2, Vector4[] chunkUV3,
        Vector3[] combinedVerts, Vector4[] combinedUV2, Vector4[] combinedUV3,
        int chunkX, int chunkZ, int chunkResolution, int totalResolutionX)
    {
        for (int z = 0; z < chunkResolution; z++)
        {
            for (int x = 0; x < chunkResolution; x++)
            {
                int chunkIdx = x + z * chunkResolution;
                int combinedX = chunkX * (chunkResolution - 1) + x;
                int combinedZ = chunkZ * (chunkResolution - 1) + z;
                int combinedIdx = combinedX + combinedZ * totalResolutionX;

                if (combinedIdx >= 0 && combinedIdx < combinedVerts.Length)
                {
                    // Adjust vertex positions so chunks align properly
                    Vector3 vertPos = chunkVerts[chunkIdx];
                    vertPos.x = combinedX;
                    vertPos.z = combinedZ;
                    
                    combinedVerts[combinedIdx] = vertPos;
                    combinedUV2[combinedIdx] = chunkUV2[chunkIdx];
                    combinedUV3[combinedIdx] = chunkUV3[chunkIdx];
                }
            }
        }
    }

    /// <summary>
    /// Generates a heightmap texture from vertex positions
    /// </summary>
    private Texture2D GenerateHeightmapTexture(Vector3[] verts, int resolutionX, int resolutionZ)
    {
        Texture2D heightmap = new Texture2D(resolutionX, resolutionZ, TextureFormat.RFloat, false, true);
        float[] heights = new float[resolutionX * resolutionZ];

        // Find min and max height for normalization
        float minHeight = float.MaxValue;
        float maxHeight = float.MinValue;

        for (int i = 0; i < verts.Length; i++)
        {
            float height = verts[i].y;
            heights[i] = height;
            if (height < minHeight) minHeight = height;
            if (height > maxHeight) maxHeight = height;
        }

        // Normalize heights to 0-1 range
        float heightRange = maxHeight - minHeight;
        if (heightRange < 0.001f) heightRange = 1f; // Prevent division by zero

        Color[] pixels = new Color[resolutionX * resolutionZ];
        for (int i = 0; i < heights.Length; i++)
        {
            float normalizedHeight = (heights[i] - minHeight) / heightRange;
            pixels[i] = new Color(normalizedHeight, normalizedHeight, normalizedHeight, 1f);
        }

        heightmap.SetPixels(pixels);
        heightmap.Apply();

        Debug.Log($"Heightmap generated: {resolutionX}x{resolutionZ}, Height range: {minHeight:F2} to {maxHeight:F2}");
        return heightmap;
    }

    /// <summary>
    /// Generates a biome map texture from biome indices
    /// </summary>
    private Texture2D GenerateBiomeMapTexture(Vector4[] uv2s, Vector4[] uv3s, int resolutionX, int resolutionZ)
    {
        Texture2D biomeMap = new Texture2D(resolutionX, resolutionZ, TextureFormat.RGBA32, false, true);
        Color[] pixels = new Color[resolutionX * resolutionZ];

        for (int i = 0; i < pixels.Length && i < uv2s.Length && i < uv3s.Length; i++)
        {
            Vector4 indices = uv2s[i];
            Vector4 weights = uv3s[i];

            int biomeIndex = (int)indices.x;
            float weight = weights.x;

            float biomeNormalized = biomeIndex / Mathf.Max(1, 19f);
            
            pixels[i] = new Color(biomeNormalized, weight, (int)indices.y / 20f, 1f);
        }

        biomeMap.SetPixels(pixels);
        biomeMap.Apply();

        Debug.Log($"Biome map generated: {resolutionX}x{resolutionZ}");
        return biomeMap;
    }

    /// <summary>
    /// Checks if the terrain data is ready for export
    /// </summary>
    public bool IsTerrainReady()
    {
        if (terrainGenerator == null)
        {
            Debug.LogWarning("TerrainMapExporter: ProcedualGenerator reference is not assigned");
            return false;
        }

        Vector3[] verts = terrainGenerator.GetVertices();
        Vector4[] uv2s = terrainGenerator.GetBiomeIndices();
        Vector4[] uv3s = terrainGenerator.GetBiomeWeights();

        if (verts == null || verts.Length == 0)
        {
            Debug.LogWarning("TerrainMapExporter: Terrain has not been generated yet. Please play the scene or ensure Start() has been called on ProcedualGenerator.");
            return false;
        }

        if (uv2s == null || uv3s == null)
        {
            Debug.LogWarning("TerrainMapExporter: Biome data is not available yet.");
            return false;
        }

        return true;
    }

    /// <summary>
    /// Retrieves terrain data from ProcedualGenerator
    /// </summary>
    private bool TryGetTerrainData(out Vector3[] verts, out Vector4[] uv2s, out Vector4[] uv3s)
    {
        verts = null;
        uv2s = null;
        uv3s = null;

        try
        {
            verts = terrainGenerator.GetVertices();
            uv2s = terrainGenerator.GetBiomeIndices();
            uv3s = terrainGenerator.GetBiomeWeights();

            // Detailed validation
            if (verts == null)
            {
                Debug.LogError("TerrainMapExporter: Vertices array is null. Terrain may not have been generated yet. Try playing the scene first.");
                return false;
            }

            if (uv2s == null)
            {
                Debug.LogError("TerrainMapExporter: Biome indices array (UV2) is null.");
                return false;
            }

            if (uv3s == null)
            {
                Debug.LogError("TerrainMapExporter: Biome weights array (UV3) is null.");
                return false;
            }

            if (verts.Length == 0)
            {
                Debug.LogError("TerrainMapExporter: Vertices array is empty. Terrain has not been generated.");
                return false;
            }

            if (uv2s.Length != verts.Length || uv3s.Length != verts.Length)
            {
                Debug.LogError($"TerrainMapExporter: Array length mismatch. Verts: {verts.Length}, UV2: {uv2s.Length}, UV3: {uv3s.Length}");
                return false;
            }

            return true;
        }
        catch (System.Exception ex)
        {
            Debug.LogError($"TerrainMapExporter: Error retrieving terrain data: {ex.Message}\n{ex.StackTrace}");
        }

        return false;
    }

    /// <summary>
    /// Creates the export folder if it doesn't exist
    /// </summary>
    private void CreateExportFolder()
    {
        string fullPath = Path.Combine(Application.dataPath, "..", exportFolder);
        if (!Directory.Exists(fullPath))
        {
            Directory.CreateDirectory(fullPath);
        }
    }

    /// <summary>
    /// Saves a texture as PNG file
    /// </summary>
    private void SaveTexture(Texture2D texture, string filename)
    {
        if (texture == null)
        {
            Debug.LogError($"TerrainMapExporter: Cannot save null texture");
            return;
        }

        CreateExportFolder();
        string fullPath = Path.Combine(Application.dataPath, "..", exportFolder, filename);
        byte[] pngData = texture.EncodeToPNG();
        File.WriteAllBytes(fullPath, pngData);
        Debug.Log($"TerrainMapExporter: Saved {filename} to {fullPath}");
    }

    /// <summary>
    /// Returns the generated heightmap texture (for runtime use)
    /// </summary>
    public Texture2D GetHeightmapTexture() => heightmapTexture;

    /// <summary>
    /// Returns the generated biome map texture (for runtime use)
    /// </summary>
    public Texture2D GetBiomeMapTexture() => biomeMapTexture;
}

